// ─── CORE NAVIGATION (Hierarchy Engine) ────────────────────────
function switchMainTab(tabId) {
    if (!checkSession()) return;
    document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('#mainTabs .tab').forEach(t => t.classList.remove('active'));
    const target = document.getElementById(tabId);
    if (target) target.classList.add('active');
    const btn = document.querySelector('#mainTabs .tab[onclick*="' + tabId + '"]');
    if (btn) btn.classList.add('active');

    const subContainer = document.getElementById('subTabs-' + tabId);
    if (subContainer) {
        const firstSub = subContainer.querySelector('.sub-tab');
        if (firstSub) {
            const subId = firstSub.getAttribute('onclick').match(/'([^']+)'/)[1];
            switchSubTab(tabId, subId);
        }
    } else {
        const allSubPages = target.querySelectorAll('.sub-page');
        allSubPages.forEach(sp => sp.classList.remove('active'));
    }
    hideForms(); closeNotice(); closeBOMWorkspace(); closeBuyerModal(); closePickerModal();
    if (tabId === 'tab1') { loadOrders(); refreshFGItems(); }
}

function switchSubTab(mainTabId, subId) {
    if (!checkSession()) return;
    const mainPage = document.getElementById(mainTabId);
    if (!mainPage) return;
    mainPage.querySelectorAll('.sub-page').forEach(sp => sp.classList.remove('active'));
    const target = document.getElementById(subId);
    if (target) target.classList.add('active');
    const subContainer = document.getElementById('subTabs-' + mainTabId);
    if (subContainer) {
        subContainer.querySelectorAll('.sub-tab').forEach(st => st.classList.remove('active'));
        const btn = subContainer.querySelector('.sub-tab[onclick*="' + subId + '"]');
        if (btn) btn.classList.add('active');
    }
    if (subId === 'n1') { loadOrders(); }
    if (subId === 'n2') { refreshFGItems(); }
}

// ─── SESSION ──────────────────────────────────────────────────
function getSessionToken() { return sessionToken || sessionStorage.getItem('sneha_session_token'); }
function setSession(token, user) { sessionToken = token; currentUser = user; sessionStorage.setItem('sneha_session_token', token); sessionStorage.setItem('sneha_user', JSON.stringify(user)); }
function clearSession() { sessionToken = null; currentUser = null; sessionStorage.removeItem('sneha_session_token'); sessionStorage.removeItem('sneha_user'); }
function checkSession() {
    if (!getSessionToken()) { showNotice('⚠️ Session Expired', 'Please login again.', 'warning'); setTimeout(redirectToLogin, 1500); return false; }
    return true;
}
function redirectToLogin() { clearSession(); document.getElementById('mainApp').classList.remove('active'); document.getElementById('loginPage').style.display = 'flex'; document.getElementById('loginPage').classList.add('active'); showLoginScreen('methodSelector'); document.getElementById('telegramPhone').value = ''; document.getElementById('telegramOtpBtn').disabled = true; currentPhoneNumber = ''; hideFullscreenLoader(); }

function showFullscreenLoader(text) { document.getElementById('loaderText').textContent = text || 'Processing...'; document.getElementById('fullscreenLoader').classList.add('active'); }
function hideFullscreenLoader() { document.getElementById('fullscreenLoader').classList.remove('active'); }

// ─── BACKEND CALLER ──────────────────────────────────────────
function callBackend(functionName, params, callback) {
    try {
        const token = getSessionToken();
        const protectedFunctions = ['createRawMaterial','getAllRawMaterials','restockItem','searchRawMaterial','getRawMaterialByItemNo','saveOrder','getOrders','getOrderBySeqNo','deleteOrder','getBuyers','saveBuyer','addBuyer','getFGItems','getBOM','saveBOM','getInternalIssues','saveInternalIssue','getExternalLinks','generateRequirementReport','generateStockReport','getPickingItems','savePick','getPickingHistory','getInternalIssueDetails','checkBOMLockStatus','lockBOM','importOrdersBulk','getStockPosition'];
        let args = [];
        if (Array.isArray(params)) { args = params.slice(); }
        else if (params !== undefined && params !== null) { args = [params]; }
        if (protectedFunctions.includes(functionName) && token) { args.push(token); }

        if (typeof google !== 'undefined' && google.script && google.script.run) {
            const runner = google.script.run
                .withSuccessHandler(function(result) { if (callback && callback.success) callback.success(result); hideFullscreenLoader(); })
                .withFailureHandler(function(error) { if (error && typeof error === 'string' && error.includes('session')) { redirectToLogin(); } if (callback && callback.failure) callback.failure(error); hideFullscreenLoader(); });
            if (typeof runner[functionName] === 'function') { runner[functionName].apply(runner, args); }
            else { if (callback && callback.failure) callback.failure(new Error('Backend function not found: ' + functionName)); hideFullscreenLoader(); }
        } else {
            mockBackendCall(functionName, args, callback);
        }
    } catch (e) { if (callback && callback.failure) callback.failure(e); hideFullscreenLoader(); }
}

