// ─── LOGIN FUNCTIONS ─────────────────────────────────────────
function showLoginScreen(screenId) { document.querySelectorAll('.login-screen').forEach(s => s.classList.remove('active')); const target = document.getElementById(screenId); if (target) target.classList.add('active'); document.querySelectorAll('.login-message-box').forEach(mb => { mb.classList.remove('show'); mb.textContent = ''; }); }
function goBackToMethodSelector() { showLoginScreen('methodSelector'); }
function goBackToSignupMethodSelector() { showLoginScreen('signupMethodSelector'); }
function selectMethod(method) { if (method === 'telegram') showLoginScreen('telegramPhoneScreen'); else showLoginScreen('emailLoginScreen'); }
function showSignupMethodSelector() { showLoginScreen('signupMethodSelector'); }
function showTelegramSignup() { showLoginScreen('telegramSignupScreen'); }
function showEmailSignup() { showLoginScreen('emailSignupScreen'); document.getElementById('e_signupName').value = ''; document.getElementById('e_signupEmail').value = ''; document.getElementById('e_signupPhone').value = ''; document.getElementById('e_signupPassword').value = ''; }
function goBackToEmailLogin() { showLoginScreen('emailLoginScreen'); }
function showLoginMessage(boxId, message, type) { const box = document.getElementById(boxId); if (box) { box.textContent = message; box.className = 'login-message-box ' + type + ' show'; } }
function hideLoginMessage(boxId) { const box = document.getElementById(boxId); if (box) { box.classList.remove('show'); box.textContent = ''; } }
let currentPhoneNumber = '';
let telegramOtpTimerInterval = null;
function handleTelegramPhoneInput(input) { input.value = input.value.replace(/\D/g, ''); if (input.value.length > 10) input.value = input.value.slice(0, 10); document.getElementById('telegramOtpBtn').disabled = input.value.length !== 10; }
function requestTelegramOTP() {
    const phoneNumber = document.getElementById('telegramPhone').value.trim();
    if (!/^[6-9]\d{9}$/.test(phoneNumber)) { showLoginMessage('telegramMessageBox', '⚠️ Please enter a valid 10-digit phone number.', 'error'); return; }
    hideLoginMessage('telegramMessageBox');
    const btn = document.getElementById('telegramOtpBtn');
    btn.disabled = true; btn.innerHTML = '⏳ Sending OTP...';
    currentPhoneNumber = phoneNumber;
    callBackend('requestLoginOTP', phoneNumber, {
        success: function(response) {
            btn.disabled = false; btn.innerHTML = '🔐 Get OTP on Telegram';
            if (response.success) {
                document.getElementById('telegramOtpPhoneDisplay').textContent = phoneNumber;
                showLoginScreen('telegramOtpScreen');
                startTelegramOTPTimer();
                for (let i = 1; i <= 6; i++) document.getElementById('t_otp' + i).value = '';
                document.getElementById('t_otp1').focus();
            } else { showLoginMessage('telegramMessageBox', '❌ ' + (response.error || 'Failed to send OTP.'), 'error'); }
        },
        failure: function(error) { btn.disabled = false; btn.innerHTML = '🔐 Get OTP on Telegram'; showLoginMessage('telegramMessageBox', '❌ Connection error. Please try again.', 'error'); }
    });
}
function telegramOtpInputHandler(currentInput, nextInputId) { currentInput.value = currentInput.value.replace(/\D/g, ''); if (currentInput.value.length === 1 && nextInputId) { const next = document.getElementById(nextInputId); if (next) { next.focus(); next.select(); } } checkTelegramOTPComplete(); }
function checkTelegramOTPComplete() { let otpComplete = true; let otpValue = ''; for (let i = 1; i <= 6; i++) { const val = document.getElementById('t_otp' + i).value; if (!val) otpComplete = false; otpValue += val; } document.getElementById('telegramVerifyBtn').disabled = !otpComplete; if (otpComplete && otpValue.length === 6) { setTimeout(function() { verifyTelegramOTPInternal(otpValue); }, 300); } }
function verifyTelegramOTP() { let otpValue = ''; for (let i = 1; i <= 6; i++) otpValue += document.getElementById('t_otp' + i).value; if (otpValue.length !== 6) { showLoginMessage('telegramOtpMessageBox', '⚠️ Please enter the complete 6-digit OTP.', 'error'); return; } verifyTelegramOTPInternal(otpValue); }
function verifyTelegramOTPInternal(otpValue) {
    hideLoginMessage('telegramOtpMessageBox');
    const btn = document.getElementById('telegramVerifyBtn');
    btn.disabled = true; btn.innerHTML = '⏳ Verifying...';
    callBackend('verifyOTPAndLogin', [currentPhoneNumber, otpValue], {
        success: function(response) {
            btn.disabled = false; btn.innerHTML = '✅ Verify & Login';
            if (response.success) { stopTelegramOTPTimer(); setSession(response.sessionToken, response.user); showLoginMessage('telegramOtpMessageBox', '✅ Login successful! Loading...', 'success'); setTimeout(function() { showMainApp(); }, 800); }
            else { showLoginMessage('telegramOtpMessageBox', '❌ ' + (response.error || 'Invalid OTP.'), 'error'); for (let i = 1; i <= 6; i++) document.getElementById('t_otp' + i).value = ''; document.getElementById('t_otp1').focus(); }
        },
        failure: function(error) { btn.disabled = false; btn.innerHTML = '✅ Verify & Login'; showLoginMessage('telegramOtpMessageBox', '❌ Connection error.', 'error'); }
    });
}
function resendTelegramOTP() { hideLoginMessage('telegramOtpMessageBox'); for (let i = 1; i <= 6; i++) document.getElementById('t_otp' + i).value = ''; document.getElementById('t_otp1').focus(); stopTelegramOTPTimer(); startTelegramOTPTimer(); callBackend('requestLoginOTP', currentPhoneNumber, { success: function(response) { if (response.success) showLoginMessage('telegramOtpMessageBox', '✅ New OTP sent!', 'success'); else showLoginMessage('telegramOtpMessageBox', '❌ ' + (response.error || 'Failed.'), 'error'); }, failure: function(error) { showLoginMessage('telegramOtpMessageBox', '❌ Service unavailable.', 'error'); } }); }
function startTelegramOTPTimer() { stopTelegramOTPTimer(); let timeLeft = 300; const display = document.getElementById('telegramOtpTimer'); const updateDisplay = function() { const mins = Math.floor(timeLeft / 60); const secs = timeLeft % 60; display.textContent = String(mins).padStart(2, '0') + ':' + String(secs).padStart(2, '0'); }; updateDisplay(); telegramOtpTimerInterval = setInterval(function() { timeLeft--; if (timeLeft <= 0) { stopTelegramOTPTimer(); display.textContent = '00:00'; showLoginMessage('telegramOtpMessageBox', '⚠️ OTP expired. Please resend.', 'error'); } else updateDisplay(); }, 1000); }
function stopTelegramOTPTimer() { if (telegramOtpTimerInterval) { clearInterval(telegramOtpTimerInterval); telegramOtpTimerInterval = null; } }
function goBackToTelegramPhone() { stopTelegramOTPTimer(); showLoginScreen('telegramPhoneScreen'); document.getElementById('telegramPhone').value = currentPhoneNumber; handleTelegramPhoneInput(document.getElementById('telegramPhone')); }
function loginWithEmail() {
    const email = document.getElementById('emailLoginInput').value.trim();
    const password = document.getElementById('passwordLoginInput').value.trim();
    if (!email) { showLoginMessage('emailLoginMessageBox', '⚠️ Please enter your email.', 'error'); return; }
    if (!password) { showLoginMessage('emailLoginMessageBox', '⚠️ Please enter your password.', 'error'); return; }
    hideLoginMessage('emailLoginMessageBox');
    const btn = document.querySelector('#emailLoginScreen .login-btn-email');
    btn.disabled = true; btn.innerHTML = '⏳ Logging in...';
    callBackend('loginWithEmail', [email, password], {
        success: function(response) {
            btn.disabled = false; btn.innerHTML = '✅ Login';
            if (response.success) { setSession(response.sessionToken, response.user); showLoginMessage('emailLoginMessageBox', '✅ Login successful! Loading...', 'success'); setTimeout(function() { showMainApp(); }, 800); }
            else { showLoginMessage('emailLoginMessageBox', '❌ ' + (response.error || 'Invalid credentials.'), 'error'); }
        },
        failure: function(error) { btn.disabled = false; btn.innerHTML = '✅ Login'; showLoginMessage('emailLoginMessageBox', '❌ Connection error.', 'error'); }
    });
}
function submitTelegramSignup() {
    const name = document.getElementById('t_signupName').value.trim();
    const phone = document.getElementById('t_signupPhone').value.trim();
    const email = document.getElementById('t_signupEmail').value.trim();
    const role = document.getElementById('t_signupRole').value;
    const chatId = document.getElementById('t_signupChatId').value.trim();
    if (!name) { showLoginMessage('telegramSignupMessageBox', '⚠️ Please enter your full name.', 'error'); return; }
    if (!/^[6-9]\d{9}$/.test(phone)) { showLoginMessage('telegramSignupMessageBox', '⚠️ Please enter a valid 10-digit phone number.', 'error'); return; }
    if (!chatId) { showLoginMessage('telegramSignupMessageBox', '⚠️ Please enter your Telegram Chat ID.', 'error'); return; }
    hideLoginMessage('telegramSignupMessageBox');
    const btn = document.getElementById('t_submitSignupBtn');
    btn.disabled = true; btn.innerHTML = '⏳ Submitting...';
    callBackend('submitRegistrationRequest', [phone, role, name, email, chatId], {
        success: function(response) { btn.disabled = false; btn.innerHTML = '📝 Submit Registration Request'; if (response.success) showLoginScreen('telegramSignupSuccessScreen'); else showLoginMessage('telegramSignupMessageBox', '❌ ' + (response.error || 'Failed.'), 'error'); },
        failure: function(error) { btn.disabled = false; btn.innerHTML = '📝 Submit Registration Request'; showLoginMessage('telegramSignupMessageBox', '❌ Connection error.', 'error'); }
    });
}
function submitEmailSignup() {
    const name = document.getElementById('e_signupName').value.trim();
    const email = document.getElementById('e_signupEmail').value.trim();
    const phone = document.getElementById('e_signupPhone').value.trim();
    const password = document.getElementById('e_signupPassword').value;
    const role = document.getElementById('e_signupRole').value;
    if (!name) { showLoginMessage('emailSignupMessageBox', '⚠️ Please enter your full name.', 'error'); return; }
    if (!email || !email.includes('@')) { showLoginMessage('emailSignupMessageBox', '⚠️ Please enter a valid email.', 'error'); return; }
    if (password.length < 6) { showLoginMessage('emailSignupMessageBox', '⚠️ Password must be at least 6 characters.', 'error'); return; }
    hideLoginMessage('emailSignupMessageBox');
    const btn = document.querySelector('#emailSignupScreen .login-btn-primary');
    btn.disabled = true; btn.innerHTML = '⏳ Submitting...';
    callBackend('submitEmailRegistration', [name, email, phone, password, role], {
        success: function(response) { btn.disabled = false; btn.innerHTML = '📝 Register'; if (response.success) { showLoginMessage('emailSignupMessageBox', '✅ Registration submitted for admin approval!', 'success'); setTimeout(function() { showLoginScreen('emailLoginScreen'); }, 2000); } else { showLoginMessage('emailSignupMessageBox', '❌ ' + (response.error || 'Failed.'), 'error'); } },
        failure: function(error) { btn.disabled = false; btn.innerHTML = '📝 Register'; showLoginMessage('emailSignupMessageBox', '❌ Connection error.', 'error'); }
    });
}

// ─── SHOW MAIN APP ─────────────────────────────────────────────
function showMainApp() {
    document.getElementById('loginPage').classList.remove('active');
    document.getElementById('loginPage').style.display = 'none';
    document.getElementById('mainApp').classList.add('active');
    document.getElementById('userDisplayName').textContent = currentUser ? (currentUser.name || currentUser.phoneNumber || currentUser.email || 'USER') : 'USER';
    initMainApp();
}

// ─── TAB MANAGEMENT ───────────────────────────────────────────
function switchMainTab(tabId) {
    if (!checkSession()) return;
    document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('#mainTabs .tab').forEach(t => t.classList.remove('active'));
    const target = document.getElementById(tabId);
    if (target) target.classList.add('active');
    const btn = document.querySelector('#mainTabs .tab[onclick*="' + tabId + '"]');
    if (btn) btn.classList.add('active');

    const subContainer = document.getElementById('subTabs-' + tabId);
    if (subContainer) {
        const firstSub = subContainer.querySelector('.sub-tab');
        if (firstSub) {
            const subId = firstSub.getAttribute('onclick').match(/'([^']+)'/)[1];
            switchSubTab(tabId, subId);
        }
    } else {
        const allSubPages = target.querySelectorAll('.sub-page');
        allSubPages.forEach(sp => sp.classList.remove('active'));
    }
    hideForms(); closeNotice(); closeBOMWorkspace(); closeBuyerModal(); closePickerModal();
    if (tabId === 'tab1') { loadOrders(); refreshFGItems(); }
}

function switchSubTab(mainTabId, subId) {
    if (!checkSession()) return;
    const mainPage = document.getElementById(mainTabId);
    if (!mainPage) return;
    mainPage.querySelectorAll('.sub-page').forEach(sp => sp.classList.remove('active'));
    const target = document.getElementById(subId);
    if (target) target.classList.add('active');
    const subContainer = document.getElementById('subTabs-' + mainTabId);
    if (subContainer) {
        subContainer.querySelectorAll('.sub-tab').forEach(st => st.classList.remove('active'));
        const btn = subContainer.querySelector('.sub-tab[onclick*="' + subId + '"]');
        if (btn) btn.classList.add('active');
    }
    if (subId === 'n1') { loadOrders(); }
    if (subId === 'n2') { refreshFGItems(); }
}

// ─── FORM VISIBILITY ──────────────────────────────────────────
