// ─── RAW MATERIAL FUNCTIONS ──────────────────────────────────
function generateAndDisplayItemNo() { const year = new Date().getFullYear(); callBackend('getAllRawMaterials', null, { success: function(response) { let maxSeq = 0; if (response.success && response.items) { response.items.forEach(item => { const itemNo = item['ITEM NO'] || ''; if (itemNo.startsWith('RM-' + year + '-')) { const seq = parseInt(itemNo.split('-')[2]); if (!isNaN(seq) && seq > maxSeq) maxSeq = seq; } }); } const nextSeq = maxSeq + 1; document.getElementById('c_itemNo').value = 'RM-' + year + '-' + String(nextSeq).padStart(3, '0'); itemCounter = nextSeq + 1; }, failure: function() { const seq = String(itemCounter).padStart(3, '0'); document.getElementById('c_itemNo').value = 'RM-' + year + '-' + seq; itemCounter++; } }); }
function previewImage(event) { const file = event.target.files[0]; const preview = document.getElementById('c_imagePreview'); if (file) { const reader = new FileReader(); reader.onload = function(e) { preview.src = e.target.result; preview.style.display = 'block'; }; reader.readAsDataURL(file); } else { preview.style.display = 'none'; } }
function previewRestockImage(event) { const file = event.target.files[0]; const preview = document.getElementById('r_imagePreview'); if (file) { const reader = new FileReader(); reader.onload = function(e) { preview.src = e.target.result; preview.style.display = 'block'; }; reader.readAsDataURL(file); } else { preview.style.display = 'none'; } }
function addItem() { if (!checkSession()) return; const itemNo = document.getElementById('c_itemNo').value; const itemName = document.getElementById('c_itemName').value.trim(); const cat = document.getElementById('c_cat').value.trim(); const subCat = document.getElementById('c_subCat').value.trim(); const size = document.getElementById('c_size').value.trim(); const color = document.getElementById('c_color').value.trim(); const uom = document.getElementById('c_uom').value; const supplier = document.getElementById('c_supplier').value.trim(); const supplierGst = document.getElementById('c_supplierGst').value.trim().toUpperCase(); const leadTime = parseInt(document.getElementById('c_leadTime').value) || 0; const personInCharge = document.getElementById('c_personInCharge').value.trim(); if (!itemName) { showNotice('⚠️ Validation Error', 'Please enter Item Name', 'warning'); return; } if (!cat) { showNotice('⚠️ Validation Error', 'Please enter Category', 'warning'); return; } if (!subCat) { showNotice('⚠️ Validation Error', 'Please enter Sub Category', 'warning'); return; } if (!size) { showNotice('⚠️ Validation Error', 'Please enter Size', 'warning'); return; } if (!color) { showNotice('⚠️ Validation Error', 'Please enter Color', 'warning'); return; } if (!uom) { showNotice('⚠️ Validation Error', 'Please select UOM', 'warning'); return; } if (!supplier) { showNotice('⚠️ Validation Error', 'Please enter Supplier name', 'warning'); return; } if (!supplierGst) { showNotice('⚠️ Validation Error', 'Please enter Supplier GST No.', 'warning'); return; } if (!personInCharge) { showNotice('⚠️ Validation Error', 'Please enter Person In Charge', 'warning'); return; } const gstRegex = /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z]{1}[1-9A-Z]{1}[Z]{1}[0-9A-Z]{1}$/; if (!gstRegex.test(supplierGst)) { showNotice('⚠️ Validation Error', 'Please enter a valid GSTIN', 'warning'); return; } const imagePreview = document.getElementById('c_imagePreview'); let imageData = ''; if (imagePreview.style.display !== 'none' && imagePreview.src) { imageData = imagePreview.src; } const itemData = { itemNo, itemName, cat, subCat, size, color, uom, supplier, supplierGst, leadTime, personInCharge, imageUrl: imageData }; const btn = document.getElementById('c_submitBtn'); btn.disabled = true; btn.innerHTML = '<span class="spinner"></span> Creating...'; showFullscreenLoader('Creating item...'); callBackend('createRawMaterial', itemData, { success: function(response) { btn.disabled = false; btn.innerHTML = '➕ Add Item'; hideFullscreenLoader(); if (response.success) { showNotice('✅ Success', 'Item Added!\n\nItem No: ' + response.itemNo, 'success'); generateAndDisplayItemNo(); document.getElementById('c_itemName').value = ''; document.getElementById('c_cat').value = ''; document.getElementById('c_subCat').value = ''; document.getElementById('c_size').value = ''; document.getElementById('c_color').value = ''; document.getElementById('c_uom').value = ''; document.getElementById('c_supplier').value = ''; document.getElementById('c_supplierGst').value = ''; document.getElementById('c_leadTime').value = ''; document.getElementById('c_personInCharge').value = ''; document.getElementById('c_imagePreview').style.display = 'none'; document.getElementById('c_imageUpload').value = ''; loadRawMaterialsForTypeahead(); } else { showNotice('❌ Error', response.error || 'Failed to create item.', 'error'); } }, failure: function(error) { btn.disabled = false; btn.innerHTML = '➕ Add Item'; hideFullscreenLoader(); showNotice('❌ Error', error.message || 'Service unavailable.', 'error'); } }); }
function loadRawMaterialsForTypeahead() { if (!checkSession()) return; callBackend('getAllRawMaterials', null, { success: function(response) { if (response.success) { allRawMaterials = response.items || []; } }, failure: function(error) { console.error('Failed to load raw materials:', error); } }); }
function searchItemTypeahead(query) { const dropdown = document.getElementById('typeaheadDropdown'); if (!query || query.length < 2) { dropdown.classList.remove('show'); return; } const results = allRawMaterials.filter(item => (item['ITEM NO'] && item['ITEM NO'].toLowerCase().includes(query.toLowerCase())) || (item['ITEM NAME'] && item['ITEM NAME'].toLowerCase().includes(query.toLowerCase()))); if (results.length === 0) { dropdown.classList.remove('show'); return; } dropdown.innerHTML = ''; results.forEach(item => { const div = document.createElement('div'); div.className = 'typeahead-item'; div.innerHTML = '<span class="item-no">' + item['ITEM NO'] + '</span><span class="item-name">' + item['ITEM NAME'] + '</span>'; div.onclick = function() { selectRestockItem(item); dropdown.classList.remove('show'); }; dropdown.appendChild(div); }); dropdown.classList.add('show'); }
function selectRestockItem(item) { selectedRestockItem = item; document.getElementById('r_searchInput').value = item['ITEM NO'] + ' - ' + item['ITEM NAME']; document.getElementById('typeaheadDropdown').classList.remove('show'); document.getElementById('r_detailNo').textContent = item['ITEM NO'] || '-'; document.getElementById('r_detailName').textContent = item['ITEM NAME'] || '-'; document.getElementById('r_detailCat').textContent = item['CAT'] || '-'; document.getElementById('r_detailSubCat').textContent = item['SUB CAT'] || '-'; document.getElementById('r_detailSize').textContent = item['SIZE'] || '-'; document.getElementById('r_detailColor').textContent = item['COLOR'] || '-'; document.getElementById('r_detailUom').textContent = item['UOM'] || '-'; document.getElementById('r_detailSupplier').textContent = item['SUPPLIER'] || '-'; document.getElementById('r_detailPerson').textContent = item['PERSON IN CHARGE'] || '-'; const imgElement = document.getElementById('r_detailImage'); const placeholder = document.getElementById('r_placeholderImage'); const imageUrl = item['IMAGE URL'] || ''; if (imageUrl && (imageUrl.startsWith('data:image') || imageUrl.startsWith('https://drive') || imageUrl.startsWith('https://via.placeholder.com'))) { imgElement.src = imageUrl; imgElement.style.display = 'block'; placeholder.style.display = 'none'; } else { imgElement.style.display = 'none'; placeholder.style.display = 'flex'; } document.getElementById('itemDetailsPreview').classList.add('show'); document.getElementById('restockInputs').style.display = 'block'; document.getElementById('r_additionalQty').value = ''; document.getElementById('r_godown').value = 'G-01'; document.getElementById('r_location').value = 'Main Storage'; document.getElementById('r_imagePreview').style.display = 'none'; document.getElementById('r_imageUpload').value = ''; document.getElementById('r_additionalQty').focus(); }
function restockItem() { if (!checkSession()) return; if (!selectedRestockItem) { showNotice('⚠️ Error', 'Please select an item first.', 'warning'); return; } const additionalQty = parseInt(document.getElementById('r_additionalQty').value); if (!additionalQty || additionalQty <= 0) { showNotice('⚠️ Error', 'Please enter a valid additional quantity.', 'warning'); return; } const godown = document.getElementById('r_godown').value.trim() || 'G-01'; const location = document.getElementById('r_location').value.trim() || 'Main Storage'; const imagePreview = document.getElementById('r_imagePreview'); let imageData = ''; if (imagePreview.style.display !== 'none' && imagePreview.src) { imageData = imagePreview.src; } const itemNo = selectedRestockItem['ITEM NO']; const btn = document.querySelector('#restockForm .btn-success'); btn.disabled = true; btn.innerHTML = '<span class="spinner"></span> Restocking...'; showFullscreenLoader('Restocking item...'); callBackend('restockItem', [itemNo, additionalQty, godown, location, imageData], { success: function(response) { btn.disabled = false; btn.innerHTML = '📥 Restock'; hideFullscreenLoader(); if (response.success) { showNotice('✅ Success', 'Restocked ' + additionalQty + ' ' + selectedRestockItem['UOM'] + ' of ' + itemNo + '\nNew Stock: ' + response.newStock + '\nGodown: ' + godown + '\nLocation: ' + location, 'success'); document.getElementById('r_additionalQty').value = ''; loadRawMaterialsForTypeahead(); document.getElementById('r_godown').value = 'G-01'; document.getElementById('r_location').value = 'Main Storage'; document.getElementById('r_imagePreview').style.display = 'none'; document.getElementById('r_imageUpload').value = ''; } else { showNotice('❌ Error', response.error || 'Failed to restock.', 'error'); } }, failure: function(error) { btn.disabled = false; btn.innerHTML = '📥 Restock'; hideFullscreenLoader(); showNotice('❌ Error', error.message || 'Service unavailable. Please try again.', 'error'); } }); }

// ─── EXCEL IMPORT ─────────────────────────────────────────────
function exportExcelTemplate() { const headers = ['ITEM NAME','CAT','SUB CAT','SIZE','COLOR','UOM','SUPPLIER','SUPPLIER GST NO.','LEAD TIME','PERSON IN CHARGE']; let csvContent = headers.join(',') + '\n'; csvContent += 'Sample Item,Category,SubCategory,Medium,Red,KG,Supplier,22AAAAA0000A1Z5,7,John Doe\n'; for (let i = 0; i < 5; i++) csvContent += '\n'; const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' }); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = 'item_template.csv'; document.body.appendChild(link); link.click(); document.body.removeChild(link); }
function importExcelData(event) { const file = event.target.files[0]; const statusEl = document.getElementById('uploadStatus'); if (!file) { showNotice('⚠️ Error', 'No file selected.', 'warning'); return; } if (!checkSession()) { document.getElementById('excelUpload').value = ''; return; } statusEl.innerHTML = '<span class="spinner" style="width:16px;height:16px;"></span> Processing...'; showFullscreenLoader('Importing items...'); const reader = new FileReader(); reader.onload = function(e) { try { const text = e.target.result; const lines = text.split('\n').filter(line => line.trim()); if (lines.length < 2) { showNotice('⚠️ Error', 'No data found in file.', 'warning'); statusEl.textContent = '❌ No data found'; document.getElementById('excelUpload').value = ''; hideFullscreenLoader(); return; } const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, '')); const requiredHeaders = ['ITEM NAME','CAT','SUB CAT','SIZE','COLOR','UOM']; const missingHeaders = requiredHeaders.filter(h => !headers.includes(h)); if (missingHeaders.length > 0) { showNotice('⚠️ Error', 'Missing required columns: ' + missingHeaders.join(', '), 'warning'); statusEl.textContent = '❌ Invalid template'; document.getElementById('excelUpload').value = ''; hideFullscreenLoader(); return; } const nameIdx = headers.indexOf('ITEM NAME'); const catIdx = headers.indexOf('CAT'); const subCatIdx = headers.indexOf('SUB CAT'); const sizeIdx = headers.indexOf('SIZE'); const colorIdx = headers.indexOf('COLOR'); const uomIdx = headers.indexOf('UOM'); const supplierIdx = headers.indexOf('SUPPLIER'); const gstIdx = headers.indexOf('SUPPLIER GST NO.'); const leadTimeIdx = headers.indexOf('LEAD TIME'); const personIdx = headers.indexOf('PERSON IN CHARGE'); let successCount = 0; let errorCount = 0; const year = new Date().getFullYear(); callBackend('getAllRawMaterials', null, { success: function(resp) { let maxSeq = 0; if (resp.success && resp.items) { resp.items.forEach(item => { const itemNo = item['ITEM NO'] || ''; if (itemNo.startsWith('RM-' + year + '-')) { const seq = parseInt(itemNo.split('-')[2]); if (!isNaN(seq) && seq > maxSeq) maxSeq = seq; } }); } const rows = lines.slice(1); let totalRows = rows.length; let processed = 0; rows.forEach(function(rowStr) { const cols = rowStr.split(',').map(c => c.trim().replace(/^"|"$/g, '')); if (cols.length <= Math.max(nameIdx, catIdx, subCatIdx, sizeIdx, colorIdx, uomIdx, supplierIdx, gstIdx, leadTimeIdx, personIdx)) { processed++; return; } const itemName = cols[nameIdx] || ''; const cat = cols[catIdx] || ''; const subCat = cols[subCatIdx] || ''; const size = cols[sizeIdx] || ''; const color = cols[colorIdx] || ''; const uom = cols[uomIdx] || 'KG'; const supplier = cols[supplierIdx] || ''; const supplierGst = cols[gstIdx] || ''; const leadTime = parseInt(cols[leadTimeIdx]) || 0; const personInCharge = cols[personIdx] || ''; if (!itemName || !cat || !subCat || !size || !color || !supplier) { errorCount++; processed++; return; } maxSeq++; const itemNo = 'RM-' + year + '-' + String(maxSeq).padStart(3, '0'); const itemData = { itemNo, itemName, cat, subCat, size, color, uom, supplier, supplierGst, leadTime, personInCharge, imageUrl: '' }; callBackend('createRawMaterial', itemData, { success: function(response) { if (response.success) successCount++; else errorCount++; processed++; updateStatus(); }, failure: function() { errorCount++; processed++; updateStatus(); } }); }); function updateStatus() { if (processed >= totalRows) { hideFullscreenLoader(); if (errorCount === 0 && successCount > 0) { statusEl.textContent = '✅ Imported ' + successCount + ' items'; showNotice('✅ Success', 'Imported ' + successCount + ' item(s) successfully!', 'success'); } else if (successCount > 0) { statusEl.textContent = '⚠️ ' + successCount + ' imported, ' + errorCount + ' failed'; showNotice('⚠️ Partial Success', successCount + ' imported, ' + errorCount + ' failed.', 'warning'); } else { statusEl.textContent = '❌ Import failed: ' + errorCount + ' errors'; showNotice('❌ Error', 'Failed to import items. ' + errorCount + ' errors.', 'error'); } loadRawMaterialsForTypeahead(); document.getElementById('excelUpload').value = ''; } } if (totalRows === 0) { statusEl.textContent = '❌ No valid data rows'; showNotice('⚠️ Error', 'No valid data rows found.', 'warning'); document.getElementById('excelUpload').value = ''; hideFullscreenLoader(); } }, failure: function(error) { statusEl.textContent = '❌ Failed to load existing items'; showNotice('❌ Error', 'Failed to load existing items: ' + error.message, 'error'); document.getElementById('excelUpload').value = ''; hideFullscreenLoader(); } }); } catch (error) { statusEl.textContent = '❌ Parse error'; showNotice('❌ Error', 'Failed to parse file: ' + error.message, 'error'); document.getElementById('excelUpload').value = ''; hideFullscreenLoader(); } }; reader.readAsText(file); }

// ─── ORDER MANAGEMENT ─────────────────────────────────────────
function generateOrderNo() { const year = new Date().getFullYear(); const seq = String(orderCounter).padStart(3, '0'); document.getElementById('order_seqNo').value = 'PO-' + year + '-' + seq + '-01'; orderCounter++; }
function setDefaultDates() { const today = new Date().toISOString().split('T')[0]; document.getElementById('order_date').value = today; document.getElementById('order_buyerOrderDate').value = today; const deliveryDate = new Date(); deliveryDate.setDate(deliveryDate.getDate() + 30); document.getElementById('order_deliveryDate').value = deliveryDate.toISOString().split('T')[0]; calculateLeadTime(); }
function calculateLeadTime() { const orderDate = document.getElementById('order_date').value; const deliveryDate = document.getElementById('order_deliveryDate').value; if (orderDate && deliveryDate) { const start = new Date(orderDate); const end = new Date(deliveryDate); const diffTime = Math.abs(end - start); const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); document.getElementById('order_leadTime').value = diffDays; const plannedDate = new Date(end); plannedDate.setDate(plannedDate.getDate() - diffDays); document.getElementById('order_plannedIssuance').value = plannedDate.toISOString().split('T')[0]; } }
function generateFGItems() { const count = parseInt(document.getElementById('order_fgCount').value); if (!count || count < 1 || count > 20) { showNotice('⚠️ Error', 'Please enter a number between 1 and 20.', 'warning'); return; } const container = document.getElementById('fgItemsContainer'); let html = '<div style="overflow-x:auto;"><table style="width:100%;border-collapse:collapse;min-width:1000px;font-size:0.9rem;"><thead><tr style="background:#0f172a;"><th style="padding:8px;border:1px solid #334155;text-align:center;white-space:nowrap;">FG #</th><th style="padding:8px;border:1px solid #334155;text-align:center;white-space:nowrap;">DESIGN *</th><th style="padding:8px;border:1px solid #334155;text-align:center;white-space:nowrap;">COLOR *</th>'; SIZE_OPTIONS.forEach(size => { html += '<th style="padding:8px;border:1px solid #334155;text-align:center;white-space:nowrap;min-width:50px;">' + size + '</th>'; }); html += '<th style="padding:8px;border:1px solid #334155;text-align:center;white-space:nowrap;min-width:80px;">TOTAL</th></tr></thead><tbody>'; orderFGItems = []; for (let i = 0; i < count; i++) { const fgItem = { id: i + 1, sizes: {} }; SIZE_OPTIONS.forEach(size => { fgItem.sizes[size] = 0; }); orderFGItems.push(fgItem); html += '<tr><td style="padding:8px;border:1px solid #334155;text-align:center;font-weight:600;">FG-' + String(i + 1).padStart(2, '0') + '</td><td style="padding:8px;border:1px solid #334155;"><input type="text" class="fg-design" data-fg="' + i + '" placeholder="Design" style="width:100%;min-width:70px;padding:4px 6px;font-size:0.85rem;" /></td><td style="padding:8px;border:1px solid #334155;"><input type="text" class="fg-color" data-fg="' + i + '" placeholder="Color" style="width:100%;min-width:70px;padding:4px 6px;font-size:0.85rem;" /></td>'; SIZE_OPTIONS.forEach(size => { html += '<td style="padding:4px;border:1px solid #334155;text-align:center;"><input type="number" class="fg-size-input" data-fg="' + i + '" data-size="' + size + '" value="0" min="0" style="width:100%;min-width:40px;padding:4px;font-size:0.8rem;text-align:center;" onchange="updateFGTotal(' + i + ')" /></td>'; }); html += '<td style="padding:8px;border:1px solid #334155;text-align:center;font-weight:700;color:#38bdf8;"><span id="fg-total-' + i + '">0</span></td></tr>'; } html += '</tbody></table></div><div style="margin-top:12px;display:flex;gap:12px;flex-wrap:wrap;"><button class="btn btn-success" onclick="calculateAllTotals()" style="background:#7c3aed;margin-top:0;">📊 Calculate All Totals</button><button class="btn btn-secondary" onclick="clearFGItems()" style="margin-top:0;">🗑️ Clear All</button></div><div style="margin-top:12px;color:#94a3b8;font-size:0.85rem;"><strong>Tip:</strong> Enter quantities per size. FG Key = Buyer Order + Design + Color</div>'; container.innerHTML = html; calculateAllTotals(); }
function updateFGTotal(fgIndex) { let total = 0; const inputs = document.querySelectorAll('.fg-size-input[data-fg="' + fgIndex + '"]'); inputs.forEach(input => { const val = parseInt(input.value) || 0; total += val; }); document.getElementById('fg-total-' + fgIndex).textContent = total; calculateTotalSum(); }
function calculateAllTotals() { const fgCount = orderFGItems.length; for (let i = 0; i < fgCount; i++) { updateFGTotal(i); } }
function calculateTotalSum() { let grandTotal = 0; const fgCount = orderFGItems.length; for (let i = 0; i < fgCount; i++) { const totalEl = document.getElementById('fg-total-' + i); if (totalEl) { grandTotal += parseInt(totalEl.textContent) || 0; } } document.getElementById('order_total').value = grandTotal; }
function clearFGItems() { const container = document.getElementById('fgItemsContainer'); container.innerHTML = '<p style="color:#94a3b8;padding:20px;text-align:center;">Enter number of FG items and click Generate Size Grid.</p>'; orderFGItems = []; document.getElementById('order_total').value = '0'; }
function getFGData() { const fgData = []; const fgCount = orderFGItems.length; for (let i = 0; i < fgCount; i++) { const sizeData = {}; const inputs = document.querySelectorAll('.fg-size-input[data-fg="' + i + '"]'); inputs.forEach(input => { const size = input.getAttribute('data-size'); const qty = parseInt(input.value) || 0; sizeData[size] = qty; }); const designInput = document.querySelector('.fg-design[data-fg="' + i + '"]'); const colorInput = document.querySelector('.fg-color[data-fg="' + i + '"]'); const design = designInput ? designInput.value.trim() : ''; const color = colorInput ? colorInput.value.trim() : ''; fgData.push({ fgIndex: i + 1, design: design, color: color, sizes: sizeData, total: parseInt(document.getElementById('fg-total-' + i).textContent) || 0 }); } return fgData; }
function saveOrder() { if (!checkSession()) return; if (isSaving) { showNotice('⚠️ Warning', 'Order is already being saved. Please wait.', 'warning'); return; } const seqNo = document.getElementById('order_seqNo').value; const orderDate = document.getElementById('order_date').value; const buyer = document.getElementById('order_buyer').value; const buyerOrderNo = document.getElementById('order_buyerOrderNo').value.trim(); const buyerOrderDate = document.getElementById('order_buyerOrderDate').value; const deliveryDate = document.getElementById('order_deliveryDate').value; const leadTime = parseInt(document.getElementById('order_leadTime').value) || 0; const plannedIssuance = document.getElementById('order_plannedIssuance').value; if (!buyer) { showNotice('⚠️ Error', 'Please select a Buyer.', 'warning'); return; } if (!buyerOrderNo) { showNotice('⚠️ Error', 'Please enter Buyer Order No.', 'warning'); return; } if (!deliveryDate) { showNotice('⚠️ Error', 'Please select Delivery Date.', 'warning'); return; } const fgData = getFGData(); if (fgData.length === 0) { showNotice('⚠️ Error', 'Please generate FG items first.', 'warning'); return; } for (let fg of fgData) { if (!fg.design) { showNotice('⚠️ Error', 'Please enter Design for FG-' + String(fg.fgIndex).padStart(2, '0'), 'warning'); return; } if (!fg.color) { showNotice('⚠️ Error', 'Please enter Color for FG-' + String(fg.fgIndex).padStart(2, '0'), 'warning'); return; } } isSaving = true; const btn = document.querySelector('.form-section .btn-success'); btn.disabled = true; btn.innerHTML = '<span class="spinner"></span> Saving...'; showFullscreenLoader('Saving order...'); let savedCount = 0; let totalErrors = 0; fgData.forEach(function(fg, index) { const sizeWiseQty = SIZE_OPTIONS.map(size => size + 'x' + (fg.sizes[size] || 0)).join(','); const fgKey = buyerOrderNo + '-' + fg.design + '-' + fg.color; const orderData = { seqNo, orderDate, buyer, buyerOrderNo, buyerOrderDate, deliveryDate, leadTime, plannedIssuance, total: fg.total || 0, sizeWiseQty, designNo: fg.design, colorNo: fg.color, fgKey, fgItems: [fg], sizes: fg.sizes }; callBackend('saveOrder', orderData, { success: function(response) { if (response.success) { savedCount++; } else { totalErrors++; if (response.error && response.error.includes('already exists')) { showNotice('⚠️ Duplicate', 'Order Already Punched for FG: ' + fgKey, 'warning'); } } checkCompletion(); }, failure: function(error) { totalErrors++; checkCompletion(); } }); function checkCompletion() { if (savedCount + totalErrors === fgData.length) { isSaving = false; btn.disabled = false; btn.innerHTML = '💾 Save Order'; hideFullscreenLoader(); if (totalErrors === 0) { showNotice('✅ Success', 'All ' + savedCount + ' FG items saved successfully!', 'success'); } else { showNotice('⚠️ Partial Success', savedCount + ' saved, ' + totalErrors + ' failed.', 'warning'); } resetOrderForm(); loadOrders(); } } }); }
function resetOrderForm() { generateOrderNo(); setDefaultDates(); document.getElementById('order_buyer').value = ''; document.getElementById('order_buyerOrderNo').value = ''; document.getElementById('order_buyerOrderDate').value = ''; document.getElementById('order_fgCount').value = ''; document.getElementById('order_total').value = '0'; clearFGItems(); document.getElementById('order_leadTime').value = '0'; document.getElementById('order_plannedIssuance').value = '-'; isSaving = false; }
