function showNoticeWithPrint(title, message, type) { const modal = document.getElementById('noticeModal'); const icon = document.getElementById('noticeIcon'); const titleEl = document.getElementById('noticeTitle'); const msgEl = document.getElementById('noticeMessage'); const printBtn = document.getElementById('noticePrintBtn'); const icons = { 'success': '✅', 'error': '❌', 'warning': '⚠️', 'info': 'ℹ️' }; icon.textContent = icons[type] || '📢'; titleEl.className = type || ''; titleEl.textContent = title || 'NOTICE!'; msgEl.textContent = message || ''; printBtn.style.display = 'inline-block'; printBtn.onclick = function() { const printContent = document.getElementById('noticeMessage').textContent; const printWindow = window.open('', '_blank', 'width=800,height=600'); printWindow.document.write('<html><head><title>Order Details</title><style>body { font-family: monospace; padding: 40px; white-space: pre-wrap; }</style></head><body><pre>' + printContent + '</pre></body></html>'); printWindow.document.close(); printWindow.print(); }; modal.style.display = 'flex'; }

