function openBOMWorkspace(fgKey) { if (!checkSession()) return; currentBomFGKey = fgKey; document.getElementById('bomWorkspace').classList.add('active'); document.getElementById('bomLoading').style.display = 'block'; document.getElementById('bomFormFields').style.display = 'none'; document.getElementById('bomLockStatus').style.display = 'none'; isBomLocked = false; callBackend('checkBOMLockStatus', fgKey, { success: function(lockResponse) { if (lockResponse.success && lockResponse.isLocked) { isBomLocked = true; document.getElementById('bomLockStatus').style.display = 'block'; document.getElementById('bomLockStatus').textContent = '🔒 ' + (lockResponse.message || 'BOM LOCKED - PICKING ALREADY STARTED'); } const fgItem = bomFGItems.find(item => (item.fgKey || item.buyerOrderNo + '-' + item.designNo + '-' + item.colorNo) === fgKey); if (fgItem) { document.getElementById('bom_buyer').value = fgItem.buyer || ''; document.getElementById('bom_buyerOrderNo').value = fgItem.buyerOrderNo || ''; document.getElementById('bom_buyerOrderDate').value = fgItem.buyerOrderDate || ''; document.getElementById('bom_designNo').value = fgItem.designNo || ''; document.getElementById('bom_colorNo').value = fgItem.colorNo || ''; document.getElementById('bom_fgKey').value = fgKey; } callBackend('getBOM', fgKey, { success: function(response) { document.getElementById('bomLoading').style.display = 'none'; document.getElementById('bomFormFields').style.display = 'block'; const saveBtn = document.getElementById('bomSaveBtn'); const addBtn = document.getElementById('bomAddMaterialBtn'); if (isBomLocked) { saveBtn.disabled = true; saveBtn.textContent = '🔒 Locked - Cannot Edit'; addBtn.disabled = true; addBtn.textContent = '🔒 Locked - Cannot Add'; document.getElementById('bomLockStatus').style.display = 'block'; } else { saveBtn.disabled = false; saveBtn.textContent = '💾 Save BOM'; addBtn.disabled = false; addBtn.textContent = '➕ Add Material Row'; } const container = document.getElementById('bomMaterialsContainer'); container.innerHTML = ''; if (response.success && response.bom) { const bom = response.bom; if (!isBomLocked) { document.getElementById('bom_createdBy').value = bom.createdBy || ''; document.getElementById('bom_createdAt').value = bom.createdAt || ''; document.getElementById('bom_lastEditedBy').value = bom.lastEditedBy || ''; document.getElementById('bom_lastEditedAt').value = bom.lastEditedAt || ''; } if (bom.materials && bom.materials.length > 0) { bom.materials.forEach(mat => { addBomMaterialRow(mat.rmItemNo, mat.consumption, mat.sizeSensitive || 'NO', mat.rmItemName || '', mat.sizeBreakup || {}); }); } else { for (let i = 0; i < 10; i++) { addBomMaterial(); } } } else { for (let i = 0; i < 10; i++) { addBomMaterial(); } } }, failure: function(error) { document.getElementById('bomLoading').style.display = 'none'; document.getElementById('bomFormFields').style.display = 'block'; showNotice('❌ Error', 'Failed to load BOM: ' + error.message, 'error'); for (let i = 0; i < 10; i++) { addBomMaterial(); } } }); }, failure: function(error) { document.getElementById('bomLoading').style.display = 'none'; document.getElementById('bomFormFields').style.display = 'block'; showNotice('❌ Error', 'Failed to check lock status: ' + error.message, 'error'); for (let i = 0; i < 10; i++) { addBomMaterial(); } } }); }
function closeBOMWorkspace() { document.getElementById('bomWorkspace').classList.remove('active'); isBomLocked = false; }
function addBomMaterial() { if (isBomLocked) return; const container = document.getElementById('bomMaterialsContainer'); const row = document.createElement('div'); row.className = 'form-row'; row.style.borderBottom = '1px solid #334155'; row.style.paddingBottom = '8px'; row.style.marginBottom = '8px'; row.innerHTML = '<div><label>RM ITEM NO</label><div class="bom-rm-predictive"><input class="bom-rm-item" placeholder="Type to search..." style="width:100%;" oninput="searchBomRM(this.value, this)" /><div class="bom-rm-dropdown"></div></div></div><div><label>RM ITEM NAME</label><input class="bom-rm-name" placeholder="Auto-populated" readonly style="width:100%;color:#94a3b8;" /></div><div><label>CONSUMPTION PER PC</label><input class="bom-consumption" type="number" placeholder="0" step="0.01" style="width:100%;" /></div><div><label>SIZE SENSITIVE</label><select class="bom-size-sensitive" onchange="toggleBomSizeSensitive(this)" style="width:100%;"><option value="NO">NO</option><option value="YES">YES</option></select></div><div style="display:flex;align-items:flex-end;"><button class="btn btn-danger" onclick="removeBomMaterial(this)" style="margin:0;padding:6px 12px;font-size:0.8rem;">✕</button></div><div class="bom-size-breakup" style="display:none;grid-column:1/-1;margin-top:8px;padding:12px;background:#0f172a;border-radius:8px;"><p style="color:#94a3b8;font-size:0.8rem;margin-bottom:8px;">Size-wise consumption (only sizes with order quantity)</p><div class="bom-size-grid" style="display:grid;grid-template-columns:repeat(auto-fit,minmax(80px,1fr));gap:8px;"></div></div>'; container.appendChild(row); const fgKey = document.getElementById('bom_fgKey').value; if (fgKey) { const sizeGrid = row.querySelector('.bom-size-grid'); populateSizeGridForBomRow(sizeGrid, fgKey); } }
function addBomMaterialRow(rmItemNo, consumption, sizeSensitive, rmItemName, sizeBreakup) { if (isBomLocked) return; const container = document.getElementById('bomMaterialsContainer'); const row = document.createElement('div'); row.className = 'form-row'; row.style.borderBottom = '1px solid #334155'; row.style.paddingBottom = '8px'; row.style.marginBottom = '8px'; row.innerHTML = '<div><label>RM ITEM NO</label><div class="bom-rm-predictive"><input class="bom-rm-item" placeholder="Type to search..." value="' + (rmItemNo || '') + '" style="width:100%;" oninput="searchBomRM(this.value, this)" /><div class="bom-rm-dropdown"></div></div></div><div><label>RM ITEM NAME</label><input class="bom-rm-name" placeholder="Auto-populated" value="' + (rmItemName || '') + '" readonly style="width:100%;color:#94a3b8;" /></div><div><label>CONSUMPTION PER PC</label><input class="bom-consumption" type="number" placeholder="0" step="0.01" value="' + (consumption || 0) + '" style="width:100%;" /></div><div><label>SIZE SENSITIVE</label><select class="bom-size-sensitive" onchange="toggleBomSizeSensitive(this)" style="width:100%;"><option value="NO" ' + (sizeSensitive === 'NO' ? 'selected' : '') + '>NO</option><option value="YES" ' + (sizeSensitive === 'YES' ? 'selected' : '') + '>YES</option></select></div><div style="display:flex;align-items:flex-end;"><button class="btn btn-danger" onclick="removeBomMaterial(this)" style="margin:0;padding:6px 12px;font-size:0.8rem;">✕</button></div><div class="bom-size-breakup" style="display:' + (sizeSensitive === 'YES' ? 'block' : 'none') + ';grid-column:1/-1;margin-top:8px;padding:12px;background:#0f172a;border-radius:8px;"><p style="color:#94a3b8;font-size:0.8rem;margin-bottom:8px;">Size-wise consumption (only sizes with order quantity)</p><div class="bom-size-grid" style="display:grid;grid-template-columns:repeat(auto-fit,minmax(80px,1fr));gap:8px;"></div></div>'; container.appendChild(row); if (sizeSensitive === 'YES') { const sizeGrid = row.querySelector('.bom-size-grid'); const fgKey = document.getElementById('bom_fgKey').value; if (fgKey) { populateSizeGridForBomRow(sizeGrid, fgKey, sizeBreakup); } } }
function populateSizeGridForBomRow(sizeGrid, fgKey, existingBreakup) { const fgItem = bomFGItems.find(item => (item.fgKey || item.buyerOrderNo + '-' + item.designNo + '-' + item.colorNo) === fgKey); let orderedSizes = SIZE_OPTIONS; let orderQuantities = {}; if (fgItem && fgItem.sizeWiseQty) { const sizeParts = fgItem.sizeWiseQty.split(','); sizeParts.forEach(part => { const match = part.match(/^(\d+)x(\d+)$/); if (match) { const size = match[1]; const qty = parseInt(match[2]) || 0; if (qty > 0) { orderQuantities[size] = qty; } } }); orderedSizes = Object.keys(orderQuantities).filter(s => SIZE_OPTIONS.includes(s)); if (orderedSizes.length === 0) orderedSizes = SIZE_OPTIONS; } sizeGrid.innerHTML = ''; orderedSizes.forEach(size => { const div = document.createElement('div'); const existingVal = (existingBreakup && existingBreakup[size]) ? existingBreakup[size] : 0; const orderQty = orderQuantities[size] || 0; div.innerHTML = '<label style="font-size:0.75rem;color:#94a3b8;">' + size + ' (' + orderQty + ' pcs)</label><input type="number" class="bom-size-qty" data-size="' + size + '" value="' + existingVal + '" step="0.01" style="width:100%;padding:4px;border-radius:4px;font-size:0.8rem;" />'; sizeGrid.appendChild(div); }); }
function toggleBomSizeSensitive(select) { if (isBomLocked) { showNotice('🔒 Locked', 'Cannot edit BOM for issued FG.', 'warning'); select.value = 'NO'; return; } const row = select.closest('.form-row'); const breakupDiv = row.querySelector('.bom-size-breakup'); const sizeGrid = row.querySelector('.bom-size-grid'); if (select.value === 'YES') { breakupDiv.style.display = 'block'; const fgKey = document.getElementById('bom_fgKey').value; if (fgKey) { populateSizeGridForBomRow(sizeGrid, fgKey); } } else { breakupDiv.style.display = 'none'; } }
function searchBomRM(query, input) { const dropdown = input.parentElement.querySelector('.bom-rm-dropdown'); if (!query || query.length < 2) { dropdown.classList.remove('show'); return; } const results = allRawMaterials.filter(item => (item['ITEM NO'] && item['ITEM NO'].toLowerCase().includes(query.toLowerCase())) || (item['ITEM NAME'] && item['ITEM NAME'].toLowerCase().includes(query.toLowerCase())) || (item['COLOR'] && item['COLOR'].toLowerCase().includes(query.toLowerCase())) || (item['SIZE'] && item['SIZE'].toLowerCase().includes(query.toLowerCase()))); if (results.length === 0) { dropdown.classList.remove('show'); return; } dropdown.innerHTML = ''; results.forEach(item => { const div = document.createElement('div'); div.className = 'bom-rm-item'; div.innerHTML = '<span class="rm-no">' + item['ITEM NO'] + '</span><span class="rm-detail">' + item['ITEM NAME'] + ' | ' + item['COLOR'] + ' | ' + item['SIZE'] + ' | ' + item['UOM'] + '</span>'; div.onclick = function() { input.value = item['ITEM NO']; const row = input.closest('.form-row'); row.querySelector('.bom-rm-name').value = item['ITEM NAME'] || ''; dropdown.classList.remove('show'); showNotice('✅ Selected', 'Selected: ' + item['ITEM NO'] + ' - ' + item['ITEM NAME'], 'success'); }; dropdown.appendChild(div); }); dropdown.classList.add('show'); }
function removeBomMaterial(btn) { if (isBomLocked) { showNotice('🔒 Locked', 'Cannot edit BOM for issued FG.', 'warning'); return; } const row = btn.closest('.form-row'); if (document.querySelectorAll('.bom-rm-item').length <= 1) { showNotice('⚠️ Warning', 'At least one material is required.', 'warning'); return; } row.remove(); }
function saveBOM() { if (!checkSession()) return; if (isBomLocked) { showNotice('🔒 Locked', 'Cannot edit BOM for issued FG.', 'warning'); return; } const fgKey = document.getElementById('bom_fgKey').value; const buyer = document.getElementById('bom_buyer').value; const buyerOrderNo = document.getElementById('bom_buyerOrderNo').value; const buyerOrderDate = document.getElementById('bom_buyerOrderDate').value; const designNo = document.getElementById('bom_designNo').value; const colorNo = document.getElementById('bom_colorNo').value; const materials = []; const rmInputs = document.querySelectorAll('.bom-rm-item'); const rmNameInputs = document.querySelectorAll('.bom-rm-name'); const consumptionInputs = document.querySelectorAll('.bom-consumption'); const sizeSensitiveSelects = document.querySelectorAll('.bom-size-sensitive'); rmInputs.forEach((input, index) => { const rmItemNo = input.value.trim(); const rmItemName = rmNameInputs[index]?.value.trim() || ''; const consumption = parseFloat(consumptionInputs[index]?.value) || 0; const sizeSensitive = sizeSensitiveSelects[index]?.value || 'NO'; let sizeBreakup = {}; if (sizeSensitive === 'YES') { const row = input.closest('.form-row'); const sizeInputs = row.querySelectorAll('.bom-size-qty'); sizeInputs.forEach(si => { const size = si.getAttribute('data-size'); const qty = parseFloat(si.value) || 0; if (qty > 0) sizeBreakup[size] = qty; }); } if (rmItemNo && consumption > 0) { materials.push({ rmItemNo, rmItemName, consumption, sizeSensitive, sizeBreakup }); } }); if (materials.length === 0) { showNotice('⚠️ Error', 'Please add at least one raw material with consumption.', 'warning'); return; } const bomData = { fgKey, buyer, buyerOrderNo, buyerOrderDate, designNo, colorNo, materials }; const btn = document.getElementById('bomSaveBtn'); btn.disabled = true; btn.innerHTML = '<span class="spinner"></span> Saving...'; showFullscreenLoader('Saving BOM...'); callBackend('saveBOM', bomData, { success: function(response) { btn.disabled = false; btn.innerHTML = '💾 Save BOM'; hideFullscreenLoader(); if (response.success) { showNotice('✅ Success', 'BOM saved successfully for ' + fgKey, 'success'); closeBOMWorkspace(); refreshFGItems(); } else { showNotice('❌ Error', response.error || 'Failed to save BOM.', 'error'); btn.disabled = false; btn.innerHTML = '💾 Save BOM'; } }, failure: function(error) { btn.disabled = false; btn.innerHTML = '💾 Save BOM'; hideFullscreenLoader(); showNotice('❌ Error', error.message || 'Service unavailable.', 'error'); } }); }

// ─── INTERNAL FG ISSUE ──────────────────────────────────────
function loadBuyerOrders() { const buyer = document.getElementById('ppm_buyer').value; const orderSelect = document.getElementById('ppm_order'); orderSelect.innerHTML = '<option value="">Select Order</option>'; document.getElementById('ppmGridContainer').style.display = 'none'; if (!buyer) return; callBackend('getOrders', null, { success: function(response) { if (response.success && response.orders) { const buyerOrders = response.orders.filter(o => o['BUYER'] === buyer && !o['INTERNAL FG ISSUED AT']); buyerOrders.forEach(order => { const option = document.createElement('option'); const seqNo = order['INTERNAL SEQUENCE NO.'] || ''; const buyerOrderNo = order['BUYER ORDER NO'] || ''; const design = order['DESIGN NO.'] || ''; const color = order['COLOR NO.'] || ''; option.value = seqNo; option.textContent = seqNo + ' - ' + buyerOrderNo + ' (' + design + '/' + color + ')'; orderSelect.appendChild(option); }); ppmOrders = buyerOrders; } }, failure: function(error) { showNotice('❌ Error', 'Failed to load orders: ' + error.message, 'error'); } }); }
function loadOrderForIssuance() { const seqNo = document.getElementById('ppm_order').value; const container = document.getElementById('ppmGridContainer'); if (!seqNo) { container.style.display = 'none'; return; } callBackend('getOrderBySeqNo', seqNo, { success: function(response) { if (response.success && response.order) { const order = response.order; let fgItems = []; try { fgItems = typeof order['FG ITEMS'] === 'string' ? JSON.parse(order['FG ITEMS']) : (order['FG ITEMS'] || []); } catch (e) { fgItems = []; } if (fgItems.length === 0) { const sizeWise = order['SIZE WISE QUANTITY'] || ''; if (sizeWise) { const parts = sizeWise.split(';'); parts.forEach(part => { const match = part.match(/^FG(\d+):(.*)$/); if (match) { const fgIndex = parseInt(match[1]); const sizes = match[2].split(','); const sizeData = {}; let total = 0; sizes.forEach(s => { const sm = s.match(/^(\d+)x(\d+)$/); if (sm) { sizeData[sm[1]] = parseInt(sm[2]) || 0; total += parseInt(sm[2]) || 0; } }); fgItems.push({ fgIndex, design: order['DESIGN NO.'] || 'DES-' + String(fgIndex).padStart(3, '0'), color: order['COLOR NO.'] || 'COL-' + String(fgIndex).padStart(3, '0'), sizes: sizeData, total }); } }); } } if (fgItems.length === 0) { container.style.display = 'none'; showNotice('⚠️ Warning', 'No FG items found for this order.', 'warning'); return; } container.style.display = 'block'; renderPPMGrid(order, fgItems); } else { container.style.display = 'none'; showNotice('❌ Error', 'Failed to load order details.', 'error'); } }, failure: function(error) { container.style.display = 'none'; showNotice('❌ Error', 'Failed to load order: ' + error.message, 'error'); } }); }
function renderPPMGrid(order, fgItems) { const grid = document.getElementById('ppmGrid'); const buyerOrderNo = order['BUYER ORDER NO'] || ''; const issueType = 'COMPLETE'; let html = '<table style="width:100%;border-collapse:collapse;min-width:1000px;font-size:0.9rem;"><thead><tr style="background:#0f172a;"><th style="padding:8px;border:1px solid #334155;text-align:center;">FG Key</th>'; SIZE_OPTIONS.forEach(size => { html += '<th style="padding:8px;border:1px solid #334155;text-align:center;min-width:50px;">' + size + '<br/><span style="font-size:0.7rem;color:#64748b;">Order</span></th>'; }); html += '<th style="padding:8px;border:1px solid #334155;text-align:center;min-width:60px;">Total<br/><span style="font-size:0.7rem;color:#64748b;">Order</span></th>'; SIZE_OPTIONS.forEach(size => { html += '<th style="padding:8px;border:1px solid #334155;text-align:center;min-width:50px;">' + size + '<br/><span style="font-size:0.7rem;color:#22c55e;">Issue</span></th>'; }); html += '<th style="padding:8px;border:1px solid #334155;text-align:center;min-width:60px;">Issue Total<br/><span style="font-size:0.7rem;color:#22c55e;">Issue</span></th><th style="padding:8px;border:1px solid #334155;text-align:center;min-width:70px;">Extra %</th></tr></thead><tbody>'; let grandTotal = 0; let grandIssueTotal = 0; fgItems.forEach((fg, idx) => { const total = fg.total || 0; grandTotal += total; const fgKey = buyerOrderNo + '-' + fg.design + '-' + fg.color; html += '<tr><td style="padding:8px;border:1px solid #334155;font-size:0.8rem;font-weight:600;color:#38bdf8;">' + fgKey + '</td>'; SIZE_OPTIONS.forEach(size => { const qty = fg.sizes[size] || 0; html += '<td style="padding:8px;border:1px solid #334155;text-align:center;color:#94a3b8;">' + qty + '</td>'; }); html += '<td style="padding:8px;border:1px solid #334155;text-align:center;font-weight:700;color:#38bdf8;">' + total + '</td>'; SIZE_OPTIONS.forEach(size => { const orderQty = fg.sizes[size] || 0; html += '<td style="padding:8px;border:1px solid #334155;text-align:center;"><input type="number" class="ppm-issue-qty" data-fg="' + idx + '" data-size="' + size + '" value="' + orderQty + '" min="0" style="width:100%;min-width:40px;padding:4px;font-size:0.8rem;text-align:center;background:#1a243b;border:1px solid #334155;border-radius:4px;color:#22c55e;" onchange="calculatePPMExtra(' + idx + ')" /></td>'; }); html += '<td style="padding:8px;border:1px solid #334155;text-align:center;font-weight:700;color:#22c55e;"><span id="ppm-issue-total-' + idx + '">' + total + '</span></td><td style="padding:8px;border:1px solid #334155;text-align:center;font-weight:700;color:#fbbf24;"><span id="ppm-extra-' + idx + '">0</span>%</td></tr>'; grandIssueTotal += total; }); html += '</tbody></table><div style="margin-top:12px;display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:12px;padding:12px;background:#0f172a;border-radius:8px;"><div><span style="color:#94a3b8;font-size:0.8rem;">Order Total</span><br/><span style="font-size:1.2rem;font-weight:700;color:#38bdf8;" id="ppmOrderTotal">' + grandTotal + '</span></div><div><span style="color:#94a3b8;font-size:0.8rem;">Issue Total</span><br/><span style="font-size:1.2rem;font-weight:700;color:#22c55e;" id="ppmIssueTotal">' + grandIssueTotal + '</span></div><div><span style="color:#94a3b8;font-size:0.8rem;">Extra %</span><br/><span style="font-size:1.2rem;font-weight:700;color:#fbbf24;" id="ppmExtraTotal">0</span>%</div></div>'; grid.innerHTML = html; window._ppmFgItems = fgItems; window._ppmOrderTotal = grandTotal; window._ppmIssueType = issueType; }
function calculatePPMExtra(fgIndex) { const fgItems = window._ppmFgItems || []; if (!fgItems[fgIndex]) return; const fg = fgItems[fgIndex]; let issueTotal = 0; let orderTotal = fg.total || 0; const inputs = document.querySelectorAll('.ppm-issue-qty[data-fg="' + fgIndex + '"]'); inputs.forEach(input => { const val = parseInt(input.value) || 0; issueTotal += val; }); document.getElementById('ppm-issue-total-' + fgIndex).textContent = issueTotal; const extra = orderTotal > 0 ? ((issueTotal - orderTotal) / orderTotal * 100) : 0; document.getElementById('ppm-extra-' + fgIndex).textContent = extra.toFixed(1); let grandIssueTotal = 0; let grandOrderTotal = window._ppmOrderTotal || 0; const allInputs = document.querySelectorAll('.ppm-issue-qty'); allInputs.forEach(inp => { grandIssueTotal += parseInt(inp.value) || 0; }); document.getElementById('ppmIssueTotal').textContent = grandIssueTotal; const extraTotal = grandOrderTotal > 0 ? ((grandIssueTotal - grandOrderTotal) / grandOrderTotal * 100) : 0; document.getElementById('ppmExtraTotal').textContent = extraTotal.toFixed(1); }
function saveInternalIssue() { if (!checkSession()) return; const buyer = document.getElementById('ppm_buyer').value; const seqNo = document.getElementById('ppm_order').value; if (!buyer || !seqNo) { showNotice('⚠️ Error', 'Please select a buyer and order.', 'warning'); return; } const issueData = []; const inputs = document.querySelectorAll('.ppm-issue-qty'); const fgItems = window._ppmFgItems || []; inputs.forEach(input => { const fgIndex = parseInt(input.getAttribute('data-fg')); const size = input.getAttribute('data-size'); const qty = parseInt(input.value) || 0; if (qty > 0) { issueData.push({ fgIndex, size, qty }); } }); if (issueData.length === 0) { showNotice('⚠️ Error', 'No quantities entered for issuance.', 'warning'); return; } const issueNo = 'PPM-' + new Date().getFullYear() + '-' + String(Math.floor(Math.random() * 9999) + 1).padStart(4, '0'); const totalOrder = parseInt(document.getElementById('ppmOrderTotal').textContent) || 0; const totalIssue = parseInt(document.getElementById('ppmIssueTotal').textContent) || 0; const extraPercent = parseFloat(document.getElementById('ppmExtraTotal').textContent) || 0; const payload = { issueNo, issueDate: new Date().toISOString().split('T')[0], buyer, orderSeqNo: seqNo, issueType: 'COMPLETE', items: issueData, totalOrder, totalIssue, extraPercent }; const btn = document.querySelector('#ppmGridContainer .btn-success'); if (btn) { btn.disabled = true; btn.innerHTML = '<span class="spinner"></span> Saving...'; } showFullscreenLoader('Saving internal issue...'); callBackend('saveInternalIssue', payload, { success: function(response) { if (btn) { btn.disabled = false; btn.textContent = '💾 Save Internal Issue'; } hideFullscreenLoader(); if (response.success) { showNotice('✅ Success', 'Internal Issue ' + issueNo + ' saved successfully!\nBOM is now LOCKED.', 'success'); clearPPMForm(); loadInternalIssues(); loadOrders(); refreshFGItems(); } else { showNotice('❌ Error', response.error || 'Failed to save issue.', 'error'); } }, failure: function(error) { if (btn) { btn.disabled = false; btn.textContent = '💾 Save Internal Issue'; } hideFullscreenLoader(); showNotice('❌ Error', error.message || 'Service unavailable.', 'error'); } }); }
function clearPPMForm() { document.getElementById('ppm_buyer').value = ''; document.getElementById('ppm_order').innerHTML = '<option value="">Select Order</option>'; document.getElementById('ppmGridContainer').style.display = 'none'; document.getElementById('ppmGrid').innerHTML = ''; window._ppmFgItems = []; }
function loadInternalIssues() { if (!checkSession()) return; document.getElementById('ppmLoading').style.display = 'block'; document.getElementById('ppmTableWrapper').style.display = 'none'; callBackend('getInternalIssues', null, { success: function(response) { document.getElementById('ppmLoading').style.display = 'none'; if (response.success) { allInternalIssues = response.issues || []; displayInternalIssues(allInternalIssues); } else { showNotice('❌ Error', response.error || 'Failed to load issues.', 'error'); document.getElementById('ppmTableBody').innerHTML = '<tr><td colspan="8" style="padding:20px;text-align:center;color:#94a3b8;">Failed to load issues.</td></tr>'; document.getElementById('ppmTableWrapper').style.display = 'block'; } }, failure: function(error) { document.getElementById('ppmLoading').style.display = 'none'; document.getElementById('ppmTableWrapper').style.display = 'block'; document.getElementById('ppmTableBody').innerHTML = '<tr><td colspan="8" style="padding:20px;text-align:center;color:#94a3b8;">Error loading issues.</td></tr>'; } }); }
function filterPPMIssues(searchTerm) { if (!searchTerm || searchTerm.length < 2) { displayInternalIssues(allInternalIssues); return; } const filtered = allInternalIssues.filter(issue => { const searchLower = searchTerm.toLowerCase(); return (issue['ISSUE NO'] && issue['ISSUE NO'].toLowerCase().includes(searchLower)) || (issue['BUYER'] && issue['BUYER'].toLowerCase().includes(searchLower)) || (issue['FG KEY'] && issue['FG KEY'].toLowerCase().includes(searchLower)) || (issue['BUYER ORDER NO'] && issue['BUYER ORDER NO'].toLowerCase().includes(searchLower)); }); displayInternalIssues(filtered); }
function displayInternalIssues(issues) { const tbody = document.getElementById('ppmTableBody'); if (!issues || issues.length === 0) { tbody.innerHTML = '<tr><td colspan="8" style="padding:20px;text-align:center;color:#94a3b8;">No internal issues found.</td></tr>'; document.getElementById('ppmTableWrapper').style.display = 'block'; return; } tbody.innerHTML = ''; issues.forEach(issue => { const tr = document.createElement('tr'); tr.innerHTML = '<td style="padding:12px;border:1px solid #334155;font-weight:600;color:#38bdf8;">' + (issue['ISSUE NO'] || '-') + '</td><td style="padding:12px;border:1px solid #334155;">' + (issue['ISSUE DATE'] || '-') + '</td><td style="padding:12px;border:1px solid #334155;">' + (issue['BUYER'] || '-') + '</td><td style="padding:12px;border:1px solid #334155;">' + (issue['BUYER ORDER NO'] || '-') + '</td><td style="padding:12px;border:1px solid #334155;font-size:0.85rem;">' + (issue['FG KEY'] || '-') + '</td><td style="padding:12px;border:1px solid #334155;">' + (issue['ISSUE TYPE'] || '-') + '</td><td style="padding:12px;border:1px solid #334155;font-weight:700;color:#fbbf24;">' + (issue['EXTRA PERCENT'] || 0) + '%</td><td style="padding:12px;border:1px solid #334155;text-align:center;"><button class="btn" onclick="viewInternalIssue(\'' + (issue['ISSUE NO'] || '') + '\')" style="margin:0;padding:6px 12px;background:#7c3aed;font-size:0.8rem;">📄 View</button></td>'; tbody.appendChild(tr); }); document.getElementById('ppmTableWrapper').style.display = 'block'; }
function viewInternalIssue(issueNo) { callBackend('getInternalIssueDetails', issueNo, { success: function(response) { if (response.success && response.issue) { const issue = response.issue; let message = '📄 Internal Issue Details\n\n═'.repeat(40) + '\nIssue No: ' + (issue['ISSUE NO'] || '-') + '\nIssue Date: ' + (issue['ISSUE DATE'] || '-') + '\nBuyer: ' + (issue['BUYER'] || '-') + '\nBuyer Order No: ' + (issue['BUYER ORDER NO'] || '-') + '\nFG Key: ' + (issue['FG KEY'] || '-') + '\nDesign No: ' + (issue['DESIGN NO.'] || '-') + '\nColor No: ' + (issue['COLOR NO.'] || '-') + '\nIssue Type: ' + (issue['ISSUE TYPE'] || '-') + '\nTotal Order: ' + (issue['TOTAL ORDER'] || 0) + '\nTotal Issue: ' + (issue['TOTAL ISSUE'] || 0) + '\nExtra %: ' + (issue['EXTRA PERCENT'] || 0) + '%\n═'.repeat(40) + '\n'; if (issue['SIZE WISE ISSUE QTY']) { message += '\n📊 Size Wise Issue:\n' + issue['SIZE WISE ISSUE QTY'].replace(/;/g, '\n'); } showNoticeWithPrint('📄 Internal Issue Details', message, 'info'); } else { showNotice('❌ Error', 'Issue not found.', 'error'); } }, failure: function(error) { showNotice('❌ Error', 'Failed to load issue details.', 'error'); } }); }
function closeInternalIssueModal() { document.getElementById('internalIssueModal').style.display = 'none'; }

// ─── REPORTS ──────────────────────────────────────────────────
function generateRequirementReport() { if (!checkSession()) return; showFullscreenLoader('Generating requirement report...'); callBackend('generateRequirementReport', null, { success: function(response) { hideFullscreenLoader(); if (response.success) { requirementReportData = response.data || []; displayRequirementReport(requirementReportData); if (requirementReportData.length === 0) { showNotice('ℹ️ Info', 'No data found. Make sure there are Internal Issues with BOM.', 'info'); } } else { showNotice('❌ Error', response.error || 'Failed to generate report.', 'error'); } }, failure: function(error) { hideFullscreenLoader(); showNotice('❌ Error', error.message || 'Service unavailable.', 'error'); } }); }
function displayRequirementReport(data) { const container = document.getElementById('requirementReportContainer'); if (!data || data.length === 0) { container.innerHTML = '<p style="color:#94a3b8;padding:20px;text-align:center;">No data found. Ensure Internal Issues exist with BOM consumption.</p>'; return; } let html = '<table class="report-table"><thead><tr>'; const headers = Object.keys(data[0]); headers.forEach(h => { html += '<th>' + h + '</th>'; }); html += '</tr></thead><tbody>'; data.forEach(row => { html += '<tr>'; headers.forEach(h => { let val = row[h] !== undefined ? row[h] : ''; if (typeof val === 'number') { val = val.toFixed(2); } html += '<td>' + val + '</td>'; }); html += '</tr>'; }); html += '</tbody></table>'; container.innerHTML = html; }
function exportRequirementReportCSV() { if (requirementReportData.length === 0) { showNotice('⚠️ Info', 'No data to export. Generate report first.', 'warning'); return; } const headers = Object.keys(requirementReportData[0]); let csv = headers.join(',') + '\n'; requirementReportData.forEach(row => { const vals = headers.map(h => { let val = row[h] !== undefined ? row[h] : ''; if (typeof val === 'string' && val.includes(',')) val = '"' + val + '"'; return val; }); csv += vals.join(',') + '\n'; }); downloadFile(csv, 'requirement_report.csv', 'text/csv'); }
function exportRequirementReportExcel() { if (requirementReportData.length === 0) { showNotice('⚠️ Info', 'No data to export. Generate report first.', 'warning'); return; } const headers = Object.keys(requirementReportData[0]); let html = '<html><head><meta charset="UTF-8"><title>Requirement Report</title></head><body><table border="1">'; html += '<tr>' + headers.map(h => '<th>' + h + '</th>').join('') + '</tr>'; requirementReportData.forEach(row => { html += '<tr>' + headers.map(h => '<td>' + (row[h] !== undefined ? row[h] : '') + '</td>').join('') + '</tr>'; }); html += '</table></body></html>'; downloadFile(html, 'requirement_report.xls', 'application/vnd.ms-excel'); }
function printRequirementReport() { const content = document.getElementById('requirementReportContainer').innerHTML; const printWindow = window.open('', '_blank', 'width=1000,height=800'); printWindow.document.write('<html><head><title>Requirement Report</title><style>body { font-family: Arial, sans-serif; padding: 20px; } table { border-collapse: collapse; width: 100%; font-size: 12px; } th, td { border: 1px solid #ccc; padding: 8px; text-align: left; } th { background: #f0f0f0; }</style></head><body><h2>PPM / Internal Issue Wise Raw Material Requirement</h2>' + content + '</body></html>'); printWindow.document.close(); printWindow.print(); }
function generateStockReport() { if (!checkSession()) return; showFullscreenLoader('Generating stock report...'); callBackend('generateStockReport', null, { success: function(response) { hideFullscreenLoader(); if (response.success) { stockReportData = response.data || []; displayStockReport(stockReportData); } else { showNotice('❌ Error', response.error || 'Failed to generate report.', 'error'); } }, failure: function(error) { hideFullscreenLoader(); showNotice('❌ Error', error.message || 'Service unavailable.', 'error'); } }); }
function displayStockReport(data) { const container = document.getElementById('stockReportContainer'); if (!data || data.length === 0) { container.innerHTML = '<p style="color:#94a3b8;padding:20px;text-align:center;">No data found.</p>'; return; } let html = '<table class="report-table"><thead><tr>'; const headers = Object.keys(data[0]); headers.forEach(h => { html += '<th>' + h + '</th>'; }); html += '</tr></thead><tbody>'; data.forEach(row => { html += '<tr>'; headers.forEach(h => { let val = row[h] !== undefined ? row[h] : ''; if (typeof val === 'number') { val = val.toFixed(2); } html += '<td>' + val + '</td>'; }); html += '</tr>'; }); html += '</tbody></table>'; container.innerHTML = html; }
function exportStockReportCSV() { if (stockReportData.length === 0) { showNotice('⚠️ Info', 'No data to export. Generate report first.', 'warning'); return; } const headers = Object.keys(stockReportData[0]); let csv = headers.join(',') + '\n'; stockReportData.forEach(row => { const vals = headers.map(h => { let val = row[h] !== undefined ? row[h] : ''; if (typeof val === 'string' && val.includes(',')) val = '"' + val + '"'; return val; }); csv += vals.join(',') + '\n'; }); downloadFile(csv, 'stock_report.csv', 'text/csv'); }
function exportStockReportExcel() { if (stockReportData.length === 0) { showNotice('⚠️ Info', 'No data to export. Generate report first.', 'warning'); return; } const headers = Object.keys(stockReportData[0]); let html = '<html><head><meta charset="UTF-8"><title>Stock Report</title></head><body><table border="1">'; html += '<tr>' + headers.map(h => '<th>' + h + '</th>').join('') + '</tr>'; stockReportData.forEach(row => { html += '<tr>' + headers.map(h => '<td>' + (row[h] !== undefined ? row[h] : '') + '</td>').join('') + '</tr>'; }); html += '</table></body></html>'; downloadFile(html, 'stock_report.xls', 'application/vnd.ms-excel'); }
function printStockReport() { const content = document.getElementById('stockReportContainer').innerHTML; const printWindow = window.open('', '_blank', 'width=1000,height=800'); printWindow.document.write('<html><head><title>Stock Report</title><style>body { font-family: Arial, sans-serif; padding: 20px; } table { border-collapse: collapse; width: 100%; font-size: 12px; } th, td { border: 1px solid #ccc; padding: 8px; text-align: left; } th { background: #f0f0f0; }</style></head><body><h2>Stock Position Report</h2>' + content + '</body></html>'); printWindow.document.close(); printWindow.print(); }
function downloadFile(content, filename, mimeType) { const blob = new Blob([content], { type: mimeType + ';charset=utf-8;' }); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = filename; document.body.appendChild(link); link.click(); document.body.removeChild(link); }

// ─── PICKER MODULE ──────────────────────────────────────────
function loadPickingItems() { if (!checkSession()) return; const container = document.getElementById('pickerContainer'); container.innerHTML = '<p style="color:#94a3b8;padding:20px;text-align:center;"><span class="spinner"></span> Loading...</p>'; callBackend('getPickingItems', null, { success: function(response) { if (response.success) { allPickingItems = response.items || []; displayPickingItems(allPickingItems); if (allPickingItems.length === 0) { container.innerHTML = '<p style="color:#94a3b8;padding:20px;text-align:center;">No open picking items found. All items are picked or no Internal Issues exist.</p>'; } } else { container.innerHTML = '<p style="color:#ef4444;padding:20px;text-align:center;">Failed to load picking items.</p>'; } }, failure: function(error) { container.innerHTML = '<p style="color:#ef4444;padding:20px;text-align:center;">Error loading items.</p>'; } }); }
function searchPickingItems(query) { if (!query || query.length < 2) { displayPickingItems(allPickingItems); return; } const filtered = allPickingItems.filter(item => { const searchLower = query.toLowerCase(); return (item.fgKey && item.fgKey.toLowerCase().includes(searchLower)) || (item.ppmNo && item.ppmNo.toLowerCase().includes(searchLower)) || (item.buyerOrderNo && item.buyerOrderNo.toLowerCase().includes(searchLower)) || (item.buyer && item.buyer.toLowerCase().includes(searchLower)) || (item.internalSeqNo && item.internalSeqNo.toLowerCase().includes(searchLower)); }); displayPickingItems(filtered); }
function displayPickingItems(items) { const container = document.getElementById('pickerContainer'); if (!items || items.length === 0) { container.innerHTML = '<p style="color:#94a3b8;padding:20px;text-align:center;">No items found.</p>'; return; } let html = '<table class="report-table"><thead><tr><th>Issue No</th><th>PPM No</th><th>FG Key</th><th>Buyer</th><th>RM Item No</th><th>RM Item Name</th><th>Required Qty</th><th>Already Picked</th><th>Balance</th><th>Action</th></tr></thead><tbody>'; items.forEach(item => { const balance = item.requiredQty - item.alreadyPicked; html += '<tr><td>' + (item.issueNo || '-') + '</td><td>' + (item.ppmNo || '-') + '</td><td style="font-size:0.85rem;color:#38bdf8;">' + (item.fgKey || '-') + '</td><td>' + (item.buyer || '-') + '</td><td>' + (item.rmItemNo || '-') + '</td><td>' + (item.rmItemName || '-') + '</td><td>' + (item.requiredQty || 0) + '</td><td>' + (item.alreadyPicked || 0) + '</td><td style="font-weight:700;color:' + (balance > 0 ? '#22c55e' : '#94a3b8') + ';">' + balance + '</td><td>' + (balance > 0 ? '<button class="btn" onclick="openPickerModal(\'' + item.fgKey + '\', \'' + item.rmItemNo + '\')" style="margin:0;padding:6px 12px;background:#7c3aed;font-size:0.8rem;">📦 Pick</button>' : '<span style="color:#22c55e;">✅ Complete</span>') + '</td></tr>'; }); html += '</tbody></table>'; container.innerHTML = html; }
function openPickerModal(fgKey, rmItemNo) { if (!checkSession()) return; document.getElementById('pickerModal').classList.add('active'); document.getElementById('pickerLoading').style.display = 'block'; document.getElementById('pickerFormContent').style.display = 'none'; const item = allPickingItems.find(i => i.fgKey === fgKey && i.rmItemNo === rmItemNo); if (item) { currentPickItem = item; document.getElementById('pick_fgKey').value = item.fgKey || ''; document.getElementById('pick_ppmNo').value = item.ppmNo || ''; document.getElementById('pick_rmItemNo').value = item.rmItemNo || ''; document.getElementById('pick_rmItemName').value = item.rmItemName || ''; document.getElementById('pick_requiredQty').value = item.requiredQty || 0; document.getElementById('pick_alreadyPicked').value = item.alreadyPicked || 0; const balance = (item.requiredQty || 0) - (item.alreadyPicked || 0); document.getElementById('pick_balanceQty').value = balance; document.getElementById('pick_availableStock').value = item.availableStock || 0; document.getElementById('pick_availableLocations').value = item.availableLocations || ''; const locationSelect = document.getElementById('pick_location'); locationSelect.innerHTML = '<option value="">Select Location</option>'; if (item.availableLocations) { const locations = item.availableLocations.split(','); locations.forEach(loc => { const opt = document.createElement('option'); opt.value = loc.trim(); opt.textContent = loc.trim(); locationSelect.appendChild(opt); }); } document.getElementById('pick_qty').value = Math.min(balance, item.availableStock || balance); document.getElementById('pick_extraQty').value = 0; document.getElementById('pickerLoading').style.display = 'none'; document.getElementById('pickerFormContent').style.display = 'block'; } else { document.getElementById('pickerLoading').textContent = 'Item not found.'; document.getElementById('pickerLoading').style.display = 'block'; } }
function closePickerModal() { document.getElementById('pickerModal').classList.remove('active'); currentPickItem = null; }
function savePick() { if (!checkSession()) return; if (!currentPickItem) { showNotice('⚠️ Error', 'No item selected for picking.', 'warning'); return; } const qty = parseInt(document.getElementById('pick_qty').value); const extraQty = parseInt(document.getElementById('pick_extraQty').value) || 0; const location = document.getElementById('pick_location').value; if (!qty || qty <= 0) { showNotice('⚠️ Error', 'Please enter a valid pick quantity.', 'warning'); return; } if (!location) { showNotice('⚠️ Error', 'Please select a location.', 'warning'); return; } const balance = parseInt(document.getElementById('pick_balanceQty').value) || 0; if (qty > balance + extraQty) { showNotice('⚠️ Error', 'Pick quantity exceeds balance + extra.', 'warning'); return; } const pickData = { fgKey: currentPickItem.fgKey, ppmNo: currentPickItem.ppmNo, internalSeqNo: currentPickItem.internalSeqNo, buyer: currentPickItem.buyer, buyerOrderNo: currentPickItem.buyerOrderNo, designNo: currentPickItem.designNo, colorNo: currentPickItem.colorNo, rmItemNo: currentPickItem.rmItemNo, rmItemName: currentPickItem.rmItemName, requiredQty: currentPickItem.requiredQty, pickedQty: qty, extraPickedQty: extraQty, godown: currentPickItem.godown || 'G-01', location: location }; const btn = document.querySelector('#pickerFormContent .btn-success'); btn.disabled = true; btn.innerHTML = '<span class="spinner"></span> Saving...'; showFullscreenLoader('Saving pick...'); callBackend('savePick', pickData, { success: function(response) { btn.disabled = false; btn.innerHTML = '📦 Confirm Pick'; hideFullscreenLoader(); if (response.success) { showNotice('✅ Success', 'Pick saved successfully! BOM is now LOCKED.', 'success'); closePickerModal(); loadPickingItems(); refreshFGItems(); } else { showNotice('❌ Error', response.error || 'Failed to save pick.', 'error'); } }, failure: function(error) { btn.disabled = false; btn.innerHTML = '📦 Confirm Pick'; hideFullscreenLoader(); showNotice('❌ Error', error.message || 'Service unavailable.', 'error'); } }); }

// ─── NOTICE CENTER ───────────────────────────────────────────
function showNotice(title, message, type) { const modal = document.getElementById('noticeModal'); const icon = document.getElementById('noticeIcon'); const titleEl = document.getElementById('noticeTitle'); const msgEl = document.getElementById('noticeMessage'); const printBtn = document.getElementById('noticePrintBtn'); const icons = { 'success': '✅', 'error': '❌', 'warning': '⚠️', 'info': 'ℹ️' }; icon.textContent = icons[type] || '📢'; titleEl.className = type || ''; titleEl.textContent = title || 'NOTICE!'; msgEl.textContent = message || ''; printBtn.style.display = 'none'; modal.style.display = 'flex'; }
function closeNotice() { document.getElementById('noticeModal').style.display = 'none'; }
function printNotice() { const printContent = document.getElementById('noticeMessage').textContent; const printWindow = window.open('', '_blank', 'width=800,height=600'); printWindow.document.write('<html><head><title>Print</title><style>body { font-family: monospace; padding: 40px; white-space: pre-wrap; }</style></head><body><pre>' + printContent + '</pre></body></html>'); printWindow.document.close(); printWindow.print(); }

// ─── LOGOUT ───────────────────────────────────────────────────
function logoutUser() { clearSession(); document.getElementById('mainApp').classList.remove('active'); document.getElementById('loginPage').style.display = 'flex'; document.getElementById('loginPage').classList.add('active'); showLoginScreen('methodSelector'); document.getElementById('telegramPhone').value = ''; document.getElementById('telegramOtpBtn').disabled = true; currentPhoneNumber = ''; showNotice('👋 Logged Out', 'You have been logged out successfully.', 'info'); setTimeout(closeNotice, 2000); }

// ─── INITIALIZATION ──────────────────────────────────────────
function initMainApp() {
    hideForms();
    generateAndDisplayItemNo();
    initializeBuyerDropdown();
    generateOrderNo();
    setDefaultDates();
    document.getElementById('fgItemsContainer').innerHTML = '<p style="color:#94a3b8;padding:20px;text-align:center;">Enter number of FG items and click Generate Size Grid.</p>';
    refreshFGItems();
    loadRawMaterialsForTypeahead();
    loadOrders();
    loadInternalIssues();
    loadBuyerDropdown();
    loadPickingItems();
    switchMainTab('tab1');
}

// ─── DOM READY ───────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', function() {
    const savedToken = sessionStorage.getItem('sneha_session_token');
    if (savedToken) {
        sessionToken = savedToken;
        const savedUser = sessionStorage.getItem('sneha_user');
        if (savedUser) { try { currentUser = JSON.parse(savedUser); } catch (e) {} }
        callBackend('validateSession', savedToken, {
            success: function(response) {
                if (response.success) { currentUser = response.user; showMainApp(); }
                else { clearSession(); document.getElementById('loginPage').classList.add('active'); document.getElementById('loginPage').style.display = 'flex'; }
            },
            failure: function() { clearSession(); document.getElementById('loginPage').classList.add('active'); document.getElementById('loginPage').style.display = 'flex'; }
        });
    } else {
        document.getElementById('loginPage').classList.add('active');
        document.getElementById('loginPage').style.display = 'flex';
    }
    document.getElementById('bomWorkspace').addEventListener('click', function(e) { if (e.target === this) closeBOMWorkspace(); });
    document.getElementById('noticeModal').addEventListener('click', function(e) { if (e.target === this) closeNotice(); });
    document.getElementById('buyerAuthPassword').addEventListener('keypress', function(e) { if (e.key === 'Enter') authenticateBuyer(); });
    document.getElementById('internalIssueModal').addEventListener('click', function(e) { if (e.target === this) closeInternalIssueModal(); });
    document.getElementById('pickerModal').addEventListener('click', function(e) { if (e.target === this) closePickerModal(); });
    document.addEventListener('click', function(e) {
        const containers = document.querySelectorAll('.typeahead-container, .bom-rm-predictive');
        containers.forEach(container => {
            if (!container.contains(e.target)) {
                const dropdown = container.querySelector('.typeahead-dropdown, .bom-rm-dropdown');
                if (dropdown) dropdown.classList.remove('show');
            }
        });
    });
    document.getElementById('c_supplierGst').addEventListener('input', function() { this.value = this.value.toUpperCase(); });
    document.getElementById('requirementReportContainer').innerHTML = '<p style="color:#94a3b8;padding:20px;text-align:center;">Click Generate Report to load data.</p>';
    document.getElementById('stockReportContainer').innerHTML = '<p style="color:#94a3b8;padding:20px;text-align:center;">Click Generate Report to load data.</p>';
});